/* Enterprise CMS - Modern Corporate Style */

:root {
    --primary-gradient: linear-gradient(135deg, #1e3c72 0%, #2a5298 50%, #1e3c72 100%);
    --accent-color: #3498db;
    --accent-hover: #2980b9;
    --success-color: #27ae60;
    --danger-color: #e74c3c;
    --text-dark: #2c3e50;
    --text-muted: #7f8c8d;
    --bg-light: #ecf0f1;
    --card-shadow: 0 10px 40px rgba(0, 0, 0, 0.15);
    --card-shadow-hover: 0 15px 50px rgba(0, 0, 0, 0.2);
}

/* å¨å±æ ·å¼ */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', -apple-system, BlinkMacSystemFont, 'Helvetica Neue', Arial, sans-serif;
    background-color: var(--bg-light);
    color: var(--text-dark);
    line-height: 1.6;
}

/* ========================================
   ç»å½é¡µé¢æ ·å¼
   ======================================== */
.login-page {
    min-height: 100vh;
    background: var(--primary-gradient);
    position: relative;
    overflow: hidden;
}

.login-page::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23ffffff' fill-opacity='0.03'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
    animation: bgMove 20s linear infinite;
}

@keyframes bgMove {
    0% { transform: translateY(0); }
    100% { transform: translateY(-60px); }
}

.login-page .card {
    background: rgba(255, 255, 255, 0.98);
    border: none;
    border-radius: 20px;
    box-shadow: var(--card-shadow);
    backdrop-filter: blur(10px);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
    overflow: hidden;
}

.login-page .card:hover {
    transform: translateY(-5px);
    box-shadow: var(--card-shadow-hover);
}

.login-page .card-header {
    background: var(--primary-gradient);
    border: none;
    padding: 2.5rem 2rem;
    border-radius: 0 !important;
}

.login-page .card-header h3 {
    font-size: 1.75rem;
    font-weight: 600;
    letter-spacing: 0.5px;
}

.login-page .card-header .logo-icon {
    width: 48px;
    height: 48px;
    margin-bottom: 0.75rem;
    filter: drop-shadow(0 2px 4px rgba(0,0,0,0.2));
}

.login-page .card-header .version-badge {
    display: inline-block;
    background: rgba(255,255,255,0.2);
    padding: 0.25rem 0.75rem;
    border-radius: 20px;
    font-size: 0.75rem;
    margin-top: 0.5rem;
}

.login-page .card-body {
    padding: 2.5rem 2rem;
}

.login-page .form-label {
    font-weight: 500;
    color: var(--text-dark);
    margin-bottom: 0.5rem;
    font-size: 0.9rem;
}

.login-page .form-control {
    border: 2px solid #e0e0e0;
    border-radius: 12px;
    padding: 0.875rem 1.25rem;
    font-size: 1rem;
    transition: all 0.3s ease;
    background: #fafafa;
}

.login-page .form-control:focus {
    border-color: var(--accent-color);
    box-shadow: 0 0 0 4px rgba(52, 152, 219, 0.1);
    background: #fff;
}

.login-page .form-control::placeholder {
    color: #aaa;
}

.login-page .btn-login {
    background: var(--primary-gradient);
    border: none;
    border-radius: 12px;
    padding: 1rem 2rem;
    font-size: 1rem;
    font-weight: 600;
    letter-spacing: 0.5px;
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
}

.login-page .btn-login::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent, rgba(255,255,255,0.2), transparent);
    transition: left 0.5s ease;
}

.login-page .btn-login:hover::before {
    left: 100%;
}

.login-page .btn-login:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 25px rgba(30, 60, 114, 0.4);
}

.login-page .card-footer {
    background: #f8f9fa;
    border-top: 1px solid #eee;
    padding: 1.25rem;
}

.login-page .card-footer small {
    color: var(--text-muted);
    font-size: 0.8rem;
}

.login-page .alert {
    border-radius: 12px;
    border: none;
    padding: 1rem 1.25rem;
    animation: shake 0.5s ease;
}

@keyframes shake {
    0%, 100% { transform: translateX(0); }
    25% { transform: translateX(-5px); }
    75% { transform: translateX(5px); }
}

/* ========================================
