   ======================================== */
.dashboard-body {
    background: #f5f7fa;
}

.navbar-dashboard {
    background: var(--primary-gradient);
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.1);
    padding: 0.75rem 0;
}

.navbar-dashboard .navbar-brand {
    font-weight: 700;
    font-size: 1.25rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.navbar-dashboard .navbar-brand svg {
    filter: drop-shadow(0 2px 4px rgba(0,0,0,0.2));
}

.navbar-dashboard .user-info {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.navbar-dashboard .user-name {
    color: rgba(255,255,255,0.9);
    font-weight: 500;
}

.navbar-dashboard .btn-logout {
    background: rgba(255,255,255,0.15);
    border: 1px solid rgba(255,255,255,0.3);
    border-radius: 8px;
    padding: 0.5rem 1rem;
    font-size: 0.875rem;
    transition: all 0.3s ease;
}

.navbar-dashboard .btn-logout:hover {
    background: rgba(255,255,255,0.25);
    border-color: rgba(255,255,255,0.5);
}

.dashboard-container {
    padding: 2rem 0;
}

.dashboard-card {
    background: #fff;
    border: none;
    border-radius: 16px;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.08);
    overflow: hidden;
    transition: transform 0.3s ease, box-shadow 0.3s ease;
    height: 100%;
}

.dashboard-card:hover {
    transform: translateY(-3px);
    box-shadow: 0 8px 25px rgba(0, 0, 0, 0.12);
}

.dashboard-card .card-header {
    background: #fff;
    border-bottom: 1px solid #eee;
    padding: 1.25rem 1.5rem;
}

.dashboard-card .card-header h5 {
    font-weight: 600;
    color: var(--text-dark);
    margin: 0;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.dashboard-card .card-header h5::before {
    content: '';
    width: 4px;
    height: 20px;
    background: var(--accent-color);
    border-radius: 2px;
}

.dashboard-card .card-body {
    padding: 1.5rem;
}

/* ä¸ä¼ è¡¨åæ ·å¼ */
.upload-zone {
    border: 2px dashed #d0d0d0;
    border-radius: 12px;
    padding: 2rem 1rem;
    text-align: center;
    transition: all 0.3s ease;
    cursor: pointer;
    margin-bottom: 1rem;
}

.upload-zone:hover {
    border-color: var(--accent-color);
    background: rgba(52, 152, 219, 0.05);
}

.upload-zone .upload-icon {
    width: 48px;
    height: 48px;
    margin-bottom: 1rem;
    opacity: 0.5;
}

.upload-zone p {
    color: var(--text-muted);
    margin-bottom: 0.5rem;
}

.upload-zone .browse-btn {
    color: var(--accent-color);
    font-weight: 500;
    cursor: pointer;
}

.upload-zone input[type="file"] {
    display: none;
}

.form-text {
    font-size: 0.8rem;
    color: var(--text-muted);
    margin-top: 0.5rem;
}

.btn-upload {
    background: var(--accent-color);
    border: none;
    border-radius: 10px;
    padding: 0.75rem 1.5rem;
    font-weight: 500;
    transition: all 0.3s ease;
}

.btn-upload:hover {
    background: var(--accent-hover);
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(52, 152, 219, 0.4);
}

/* æä»¶åè¡¨æ ·å¼ */
.file-table {
    margin-bottom: 0;
}

.file-table thead th {
    background: #f8f9fa;
    border-bottom: 2px solid #eee;
    font-weight: 600;
    color: var(--text-dark);
    padding: 1rem;
    font-size: 0.875rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.file-table tbody td {
    padding: 1rem;
    vertical-align: middle;
    border-bottom: 1px solid #f0f0f0;
}

.file-table tbody tr:hover {
    background: #fafafa;
}

.file-table .file-name {
    display: flex;
    align-items: center;
    gap: 0.75rem;
}

.file-table .file-icon {
    width: 32px;
    height: 32px;
    background: #e8f4fc;
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.file-table .file-icon svg {
    width: 16px;
    height: 16px;
    color: var(--accent-color);
}

.btn-view {
    background: transparent;
    border: 1px solid var(--accent-color);
    color: var(--accent-color);
    border-radius: 8px;
    padding: 0.375rem 1rem;
    font-size: 0.8rem;
    font-weight: 500;
    transition: all 0.3s ease;
}

.btn-view:hover {
    background: var(--accent-color);
    color: #fff;
}

.empty-state {
    text-align: center;
    padding: 3rem 1rem;
    color: var(--text-muted);
}

.empty-state svg {
    width: 64px;
    height: 64px;
    margin-bottom: 1rem;
    opacity: 0.3;
}

.empty-state p {
    margin: 0;
    font-size: 0.95rem;
}

/* Alert æ ·å¼ */
.alert-info {
    background: #e8f4fc;
    border: none;
    border-left: 4px solid var(--accent-color);
    border-radius: 8px;
    color: var(--text-dark);
}

/* ========================================
   ååºå¼è®¾è®¡
   ======================================== */
@media (max-width: 992px) {
    .dashboard-container {
        padding: 1.5rem 0;
    }

    .dashboard-card {
        margin-bottom: 1.5rem;
    }
}

@media (max-width: 768px) {
    .login-page .card {
        margin: 1rem;
        border-radius: 16px;
    }

    .login-page .card-body {
        padding: 2rem 1.5rem;
    }

    .login-page .card-header {
        padding: 2rem 1.5rem;
    }

    .login-page .card-header h3 {
        font-size: 1.5rem;
    }

    .navbar-dashboard .user-info {
        flex-direction: column;
        align-items: flex-end;
        gap: 0.5rem;
    }
}

