   ======================================== */
@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.login-page .card {
    animation: fadeInUp 0.6s ease;
}

.dashboard-card {
    animation: fadeInUp 0.4s ease;
}

.dashboard-card:nth-child(2) {
    animation-delay: 0.1s;
}

