/* Enterprise CMS - Modern Corporate Style */

:root {
    --primary-gradient: linear-gradient(135deg, #1e3c72 0%, #2a5298 50%, #1e3c72 100%);
    --accent-color: #3498db;
    --accent-hover: #2980b9;
    --success-color: #27ae60;
    --danger-color: #e74c3c;
    --text-dark: #2c3e50;
    --text-muted: #7f8c8d;
    --bg-light: #ecf0f1;
    --card-shadow: 0 10px 40px rgba(0, 0, 0, 0.15);
    --card-shadow-hover: 0 15px 50px rgba(0, 0, 0, 0.2);
}

/* å¨å±æ ·å¼ */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Segoe UI', -apple-system, BlinkMacSystemFont, 'Helvetica Neue', Arial, sans-serif;
    background-color: var(--bg-light);
    color: var(--text-dark);
    line-height: 1.6;
}

/* ========================================
